   170→    if (getuid() != 0)
   171→        return -1;
   172→
   173→    if (mode == IPTABLES_MODE) {
   174→        sprintf(cli, ip6tables_remove_chain, chain_name, chain_name, chain_name);
   175→        ret |= system(cli);
   176→        sprintf(cli, iptables_remove_chain, chain_name, chain_name, chain_name);
   177→        ret |= system(cli);
   178→    } else if (mode == FIREWALLD_MODE) {
   179→        sprintf(cli, firewalld6_remove_chain, chain_name, chain_name, chain_name);
   180→        ret |= system(cli);
   181→        sprintf(cli, firewalld_remove_chain, chain_name, chain_name, chain_name);
   182→        ret |= system(cli);
   183→    }
   184→
   185→    if (shell_stdin != NULL) {
   186→        run_cmd("exit 0");
   187→        pclose(shell_stdin);
   188→    }
   189→
   190→    return ret;
