   318→static void
   319→parse_addr_cidr(const char *str, char *host, int *cidr)
   320→{
   321→    int ret = -1, n = 0;
   322→    char *pch;
   323→
   324→    pch = strchr(str, '/');
   325→    while (pch != NULL) {
   326→        n++;
   327→        ret = pch - str;
   328→        pch = strchr(pch + 1, '/');
   329→    }
   330→    if (ret == -1) {
   331→        strcpy(host, str);
   332→        *cidr = -1;
   333→    } else {
   334→        memcpy(host, str, ret);
   335→        host[ret] = '\0';
   336→        *cidr     = atoi(str + ret + 1);
   337→    }
   338→}
