   498→/*
   499→ * Return 0,  if not match.
   500→ * Return 1,  if match black list.
   501→ * Return -1, if match white list.
   502→ */
   503→int
   504→acl_match_host(const char *host)
   505→{
   506→    struct cork_ip addr;
   507→    int ret = 0;
   508→    int err = cork_ip_init(&addr, host);
   509→
   510→    if (err) {
   511→        int host_len = strlen(host);
   512→        if (lookup_rule(&black_list_rules, host, host_len) != NULL)
   513→            ret = 1;
   514→        else if (lookup_rule(&white_list_rules, host, host_len) != NULL)
   515→            ret = -1;
   516→        return ret;
   517→    }
   518→
   519→    if (addr.version == 4) {
   520→        if (ipset_contains_ipv4(&black_list_ipv4, &(addr.ip.v4)))
   521→            ret = 1;
   522→        else if (ipset_contains_ipv4(&white_list_ipv4, &(addr.ip.v4)))
   523→            ret = -1;
   524→    } else if (addr.version == 6) {
   525→        if (ipset_contains_ipv6(&black_list_ipv6, &(addr.ip.v6)))
   526→            ret = 1;
   527→        else if (ipset_contains_ipv6(&white_list_ipv6, &(addr.ip.v6)))
   528→            ret = -1;
   529→    }
   530→
   531→    return ret;
   532→}
   533→
   534→int
   535→acl_add_ip(const char *ip)
   536→{
   537→    struct cork_ip addr;
   538→    int err = cork_ip_init(&addr, ip);
   539→    if (err) {
   540→        return -1;
   541→    }
   542→
   543→    if (addr.version == 4) {
