int
cork_ip_init(struct cork_ip *addr, const char *str)
{
    int  rc;

    /* Try IPv4 first */
    rc = cork_ipv4_init(&addr->ip.v4, str);
    if (rc == 0) {
        /* successful parse */
        addr->version = 4;
        return 0;
    }

    /* Then try IPv6 */
    cork_error_clear();
    rc = cork_ipv6_init(&addr->ip.v6, str);
    if (rc == 0) {
        /* successful parse */
        addr->version = 6;
        return 0;
    }

    /* Parse error for both address types */
    cork_parse_error("Invalid IP address: \"%s\"", str);
    return -1;
}

